fn fibonacci(n: i64) -> i64 {
    let mut a = 0;
    let mut b = 1;
    let mut idx = 0;
    while idx < n {
        let mut temp = b;
        b = a + b;
        a = temp;
        idx += 1;
    }
    return a;
}

fn sum_range(from_val: i64, to_val: i64) -> i64 {
    let mut total = 0;
    let mut idx = from_val;
    while idx < to_val {
        total += idx;
        idx += 1;
    }
    return total;
}

